"use client";

import { useState } from "react";
import { signInWithPopup, GoogleAuthProvider } from "firebase/auth";
import { auth, db } from "@/lib/firebase";
import { ref, get } from "firebase/database";
import { useRouter } from "next/navigation";
import * as OTPAuth from "otpauth";

export default function LoginPage() {
    const router = useRouter();
    const [error, setError] = useState("");
    const [show2FA, setShow2FA] = useState(false);
    const [twoFactorCode, setTwoFactorCode] = useState("");
    const [isVerifying, setIsVerifying] = useState(false);
    const [userSecret, setUserSecret] = useState("");
    const [userEmail, setUserEmail] = useState("");

    const handleGoogleLogin = async () => {
        try {
            const provider = new GoogleAuthProvider();
            const result = await signInWithPopup(auth, provider);

            // Check if user has 2FA enabled
            const userRef = ref(db, `users/${result.user.uid}`);
            const snapshot = await get(userRef);
            const userData = snapshot.val();

            if (snapshot.exists() && userData.twoFactorEnabled && userData.twoFactorSecret) {
                setUserSecret(userData.twoFactorSecret);
                setUserEmail(result.user.email || "");
                setShow2FA(true);
            } else {
                router.push("/dashboard");
            }
        } catch (err: any) {
            setError("Failed to login with Google: " + err.message);
        }
    };

    const handleVerify2FA = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setIsVerifying(true);

        try {
            const totp = new OTPAuth.TOTP({
                issuer: "Procurify Enterprise",
                label: userEmail,
                algorithm: "SHA1",
                digits: 6,
                period: 30,
                secret: userSecret
            });

            const delta = totp.validate({
                token: twoFactorCode,
                window: 1
            });

            if (delta !== null) {
                router.push("/dashboard");
            } else {
                setError("Invalid authentication code. Please check your app and try again.");
                setIsVerifying(false);
            }
        } catch (err) {
            setError("Verification error. Please contact support.");
            setIsVerifying(false);
        }
    };

    return (
        <div style={{
            display: 'flex',
            minHeight: '100vh',
            alignItems: 'center',
            justifyContent: 'center',
            background: 'var(--background)'
        }}>
            <div className="card" style={{
                maxWidth: '400px',
                width: '100%',
                textAlign: 'center',
                padding: '3rem',
                borderRadius: '32px',
                boxShadow: 'var(--shadow-xl)'
            }}>
                <div style={{
                    width: '64px',
                    height: '64px',
                    background: 'rgba(4, 156, 99, 0.1)',
                    color: 'var(--primary)',
                    borderRadius: '20px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '2rem',
                    margin: '0 auto 2rem auto'
                }}>
                    {show2FA ? "🛡️" : "🔐"}
                </div>

                <h2 style={{ marginBottom: show2FA ? '0.5rem' : '1.5rem', fontSize: '1.8rem', fontWeight: 800 }}>
                    {show2FA ? "Verify Identity" : "Secure Sign In"}
                </h2>

                {show2FA && (
                    <p style={{ color: 'var(--text-secondary)', marginBottom: '2rem', fontSize: '0.9rem' }}>
                        Enter the authentication code from your registered device to continue.
                    </p>
                )}

                {error && (
                    <div style={{
                        backgroundColor: 'rgba(239, 68, 68, 0.1)',
                        color: 'var(--error)',
                        padding: '0.75rem',
                        borderRadius: '12px',
                        fontSize: '0.85rem',
                        marginBottom: '1.5rem',
                        fontWeight: 600
                    }}>
                        {error}
                    </div>
                )}

                {!show2FA ? (
                    <button
                        onClick={handleGoogleLogin}
                        className="btn"
                        style={{
                            width: '100%',
                            border: '1px solid var(--border)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '0.75rem',
                            padding: '1rem',
                            borderRadius: '14px',
                            fontWeight: 700,
                            backgroundColor: 'white',
                            color: '#333',
                            transition: 'all 0.2s'
                        }}
                    >
                        <svg style={{ width: '20px', height: '20px' }} viewBox="0 0 24 24">
                            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.26.81-.58z" fill="#FBBC05" />
                            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                        </svg>
                        Continue with Google
                    </button>
                ) : (
                    <form onSubmit={handleVerify2FA}>
                        <div style={{ marginBottom: '1.5rem' }}>
                            <input
                                type="text"
                                placeholder="000000"
                                maxLength={6}
                                value={twoFactorCode}
                                onChange={(e) => setTwoFactorCode(e.target.value)}
                                required
                                style={{
                                    textAlign: 'center',
                                    letterSpacing: '1rem',
                                    fontSize: '2rem',
                                    fontWeight: 800,
                                    border: '2px solid var(--border)',
                                    borderRadius: '16px',
                                    padding: '1rem',
                                    width: '100%',
                                    outline: 'none',
                                    color: 'var(--primary)'
                                }}
                            />
                        </div>
                        <button
                            type="submit"
                            className="btn btn-primary"
                            disabled={isVerifying || twoFactorCode.length < 6}
                            style={{ width: '100%', padding: '1rem', borderRadius: '14px', fontWeight: 800 }}
                        >
                            {isVerifying ? "Authorizing..." : "Secure Verify"}
                        </button>
                        <button
                            type="button"
                            onClick={() => setShow2FA(false)}
                            style={{
                                background: 'none',
                                border: 'none',
                                color: 'var(--text-secondary)',
                                marginTop: '1.5rem',
                                cursor: 'pointer',
                                fontSize: '0.9rem',
                                fontWeight: 500
                            }}
                        >
                            ← Back to Sign In
                        </button>
                    </form>
                )}

                <div style={{ marginTop: '2rem', paddingTop: '1.5rem', borderTop: '1px solid var(--border)' }}>
                    <button
                        onClick={() => window.dispatchEvent(new CustomEvent('open-help-center'))}
                        style={{
                            background: 'none',
                            border: 'none',
                            color: 'var(--primary)',
                            fontSize: '0.85rem',
                            fontWeight: 700,
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '0.5rem',
                            margin: '0 auto'
                        }}
                    >
                        <span>❓</span> Need help signing in?
                    </button>
                </div>
            </div>
        </div>
    );
}
